// DMA 传输完成回调（TX）
void HAL_SPI_TxCpltCallback(SPI_HandleTypeDef *hspi)
{
    if (hspi->Instance == SPI2 )
    {
		// 拉高片选，结束本次通信 
         LCD_CS_SET;
        //  核心：通知 LVGL 刚才那块数据发完了，你可以把下一块交给我了
        if(disp_drv_ptr != NULL)
        {
            lv_disp_flush_ready(disp_drv_ptr);
        }
    }
}


